from manim import *

class GenScene(Scene):
    def construct(self):
        positions = [0.5 * LEFT + 0.5 * DOWN, ORIGIN, 0.5 * RIGHT + 0.5 * UP]
        circles = VGroup(
            Circle(color="#FB7185").move_to(positions[0]), 
            Circle(color="#FB7185", fill_opacity=1.0).set_fill(BLACK, opacity=1.0).move_to(positions[1]), 
            Circle(color="#FB7185").move_to(positions[2])
        )

        text = Text("Animo").next_to(circles, DOWN)

        for circle in circles:
            self.play(Create(circle))

        self.play(Write(text))

